/**
 * Dashboard page — protected by the isAuthenticated interrupter.
 * Displays the logged-in user's username.
 */

import type { RequestInfo } from "rwsdk/worker";

export function DashboardPage({ ctx }: RequestInfo) {
  const username = (ctx as any).username as string;

  return (
    <html lang="en">
      <head>
        <meta charSet="utf-8" />
        <meta name="viewport" content="width=device-width, initial-scale=1" />
        <title>Dashboard</title>
        <style>{`
          body { font-family: sans-serif; display: flex; justify-content: center; align-items: center; min-height: 100vh; margin: 0; background: #f5f5f5; }
          .container { background: white; padding: 2rem; border-radius: 8px; box-shadow: 0 2px 8px rgba(0,0,0,0.1); width: 400px; text-align: center; }
          h1 { margin-top: 0; }
          .username { color: #0070f3; font-weight: 700; }
          .logout-btn { display: inline-block; margin-top: 1rem; padding: 0.5rem 1.5rem; background: #d00; color: white; border: none; border-radius: 4px; font-size: 0.9rem; cursor: pointer; text-decoration: none; }
          .logout-btn:hover { background: #b00; }
        `}</style>
      </head>
      <body>
        <div className="container">
          <h1>Dashboard</h1>
          <p>
            Welcome, <span className="username">{username}</span>!
          </p>
          <form method="post" action="/logout">
            <button type="submit" className="logout-btn">Logout</button>
          </form>
        </div>
      </body>
    </html>
  );
}

/**
 * Login page — renders an HTML form for GET, handles POST for authentication.
 *
 * GET /login: renders the login form
 * POST /login: validates credentials and sets session cookie
 */

import type { RequestInfo } from "rwsdk/worker";
import { findUser } from "../users";
import { createSessionCookie } from "../session";

export async function LoginPage({ request, ctx }: RequestInfo) {
  const secret = (ctx as any).sessionSecret as string;
  const error = (ctx as any).loginError as string | undefined;

  return (
    <html lang="en">
      <head>
        <meta charSet="utf-8" />
        <meta name="viewport" content="width=device-width, initial-scale=1" />
        <title>Login</title>
        <style>{`
          body { font-family: sans-serif; display: flex; justify-content: center; align-items: center; min-height: 100vh; margin: 0; background: #f5f5f5; }
          .container { background: white; padding: 2rem; border-radius: 8px; box-shadow: 0 2px 8px rgba(0,0,0,0.1); width: 320px; }
          h1 { margin-top: 0; }
          label { display: block; margin-bottom: 0.5rem; font-weight: 600; }
          input { width: 100%; padding: 0.5rem; margin-bottom: 1rem; border: 1px solid #ccc; border-radius: 4px; box-sizing: border-box; }
          button { width: 100%; padding: 0.75rem; background: #0070f3; color: white; border: none; border-radius: 4px; font-size: 1rem; cursor: pointer; }
          button:hover { background: #0051cc; }
          .error { color: #d00; margin-bottom: 1rem; padding: 0.5rem; background: #ffeaea; border-radius: 4px; }
        `}</style>
      </head>
      <body>
        <div className="container">
          <h1>Login</h1>
          {error && <div className="error">{error}</div>}
          <form method="post" action="/login">
            <label htmlFor="username">Username</label>
            <input type="text" id="username" name="username" required />
            <label htmlFor="password">Password</label>
            <input type="password" id="password" name="password" required />
            <button type="submit">Sign In</button>
          </form>
        </div>
      </body>
    </html>
  );
}

export async function LoginPostHandler({ request, ctx }: RequestInfo) {
  const secret = (ctx as any).sessionSecret as string;

  const body = await request.text();
  const params = new URLSearchParams(body);
  const username = params.get("username");
  const password = params.get("password");

  if (!username || !password) {
    return new Response(
      renderLoginError("Username and password are required."),
      {
        status: 401,
        headers: { "Content-Type": "text/html" },
      },
    );
  }

  const user = findUser(username, password);
  if (!user) {
    return new Response(
      renderLoginError("Invalid username or password."),
      {
        status: 401,
        headers: { "Content-Type": "text/html" },
      },
    );
  }

  const cookie = await createSessionCookie(user.username, secret);
  return new Response(null, {
    status: 302,
    headers: {
      Location: "/dashboard",
      "Set-Cookie": cookie,
    },
  });
}

